"""Database models for OAuth2 auth entities."""

import datetime
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class AuthorizationCode:
    """Represents an OAuth2 authorization code grant."""
    code: str
    client_id: str
    user_id: str
    redirect_uri: str
    scope: str
    created_at: datetime.datetime = field(default_factory=datetime.datetime.utcnow)
    expires_at: Optional[datetime.datetime] = None
    is_used: bool = False

    @property
    def is_expired(self) -> bool:
        if self.expires_at is None:
            return False
        return datetime.datetime.utcnow() > self.expires_at


@dataclass
class RefreshToken:
    """Represents an OAuth2 refresh token."""
    token: str
    client_id: str
    user_id: str
    scope: str
    created_at: datetime.datetime = field(default_factory=datetime.datetime.utcnow)
    expires_at: Optional[datetime.datetime] = None
    is_revoked: bool = False

    @property
    def is_expired(self) -> bool:
        if self.expires_at is None:
            return False
        return datetime.datetime.utcnow() > self.expires_at

    @property
    def is_valid(self) -> bool:
        return not self.is_revoked and not self.is_expired


@dataclass
class TokenStore:
    """In-memory token store. Replace with DB-backed store in production."""
    _auth_codes: dict = field(default_factory=dict)
    _refresh_tokens: dict = field(default_factory=dict)

    def store_auth_code(self, auth_code: AuthorizationCode) -> None:
        self._auth_codes[auth_code.code] = auth_code

    def get_auth_code(self, code: str) -> Optional[AuthorizationCode]:
        return self._auth_codes.get(code)

    def store_refresh_token(self, refresh_token: RefreshToken) -> None:
        self._refresh_tokens[refresh_token.token] = refresh_token

    def get_refresh_token(self, token: str) -> Optional[RefreshToken]:
        return self._refresh_tokens.get(token)

    def revoke_refresh_token(self, token: str) -> bool:
        rt = self._refresh_tokens.get(token)
        if rt:
            rt.is_revoked = True
            return True
        return False

"""OAuth2 Authorization Routes."""

import logging
from typing import Optional

logger = logging.getLogger(__name__)


class AuthorizationEndpoint:
    """Handles OAuth2 /authorize requests."""

    def __init__(self, token_manager):
        self.token_manager = token_manager

    def handle_authorize(self, client_id: str, redirect_uri: str,
                         scope: str, user_id: str, response_type: str = "code") -> dict:
        """Process an authorization request and return a redirect with auth code."""
        if response_type != "code":
            return {"error": "unsupported_response_type"}

        result = self.token_manager.create_authorization_code(
            client_id=client_id,
            redirect_uri=redirect_uri,
            scope=scope,
            user_id=user_id
        )

        logger.info(f"Authorization code issued for client {client_id}, user {user_id}")
        return {
            "redirect_uri": f"{redirect_uri}?code={result['code']}",
            "code": result["code"],
            "expires_in": result["expires_in"]
        }


class TokenEndpoint:
    """Handles OAuth2 /token requests."""

    def __init__(self, token_manager):
        self.token_manager = token_manager

    def handle_token_request(self, grant_type: str, client_id: str,
                              code: Optional[str] = None,
                              refresh_token: Optional[str] = None,
                              redirect_uri: Optional[str] = None,
                              scope: Optional[str] = None) -> dict:
        """Exchange authorization code or refresh token for access tokens."""
        if grant_type == "authorization_code":
            return self._handle_code_exchange(client_id, code, redirect_uri)
        elif grant_type == "refresh_token":
            return self._handle_refresh(client_id, refresh_token, scope)
        else:
            return {"error": "unsupported_grant_type"}

    def _handle_code_exchange(self, client_id: str, code: str, redirect_uri: str) -> dict:
        auth_code_data = self.token_manager.validate_authorization_code(code)
        if not auth_code_data:
            return {"error": "invalid_grant"}
        if auth_code_data["client_id"] != client_id:
            return {"error": "invalid_grant"}
        if auth_code_data["redirect_uri"] != redirect_uri:
            return {"error": "invalid_grant"}

        refresh_result = self.token_manager.create_refresh_token(
            client_id=client_id,
            user_id=auth_code_data["user_id"],
            scope=auth_code_data["scope"]
        )

        return {
            "token_type": "Bearer",
            "refresh_token": refresh_result["token"],
            "scope": auth_code_data["scope"],
            "expires_in": refresh_result["expires_in"]
        }

    def _handle_refresh(self, client_id: str, refresh_token: str, scope: str) -> dict:
        # TODO: implement refresh token rotation
        return {"error": "not_implemented"}

